import{b as t,a as e,_ as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as l,o as r,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"認証管理とログイン端末管理","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Safety/authentication-and-login-devices.md","filePath":"ja-JP/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),n={name:"ja-JP/Safety/authentication-and-login-devices.md"};function h(s,a,c,p,_,u){return r(),o("div",null,[...a[0]||(a[0]=[d('<h1 id="認証管理とログイン端末管理" tabindex="-1">認証管理とログイン端末管理 <a class="header-anchor" href="#認証管理とログイン端末管理" aria-label="Permalink to &quot;認証管理とログイン端末管理&quot;">​</a></h1><p>認証管理では、管理画面やユーザー側ページへのログイン方法、ログイン済み端末、アクセス状態を確認できます。</p><h2 id="管理画面ログイン" tabindex="-1">管理画面ログイン <a class="header-anchor" href="#管理画面ログイン" aria-label="Permalink to &quot;管理画面ログイン&quot;">​</a></h2><p>管理者は管理画面ログインから ImgBed の設定やファイル管理へ入ります。</p><p><img src="'+t+'" alt="管理画面ログイン" loading="lazy"></p><p>管理者アカウントは強い権限を持つため、パスワードや認証情報は安全に管理してください。</p><h2 id="ユーザー側ログイン" tabindex="-1">ユーザー側ログイン <a class="header-anchor" href="#ユーザー側ログイン" aria-label="Permalink to &quot;ユーザー側ログイン&quot;">​</a></h2><p>ユーザー向けのログイン画面も用意されています。</p><p><img src="'+e+'" alt="ユーザー側ログイン" loading="lazy"></p><p>公開アップロードや限定公開機能を使う場合、ユーザー側ログインを組み合わせることで、誰が操作したかを追いやすくなります。</p><h2 id="認証管理画面" tabindex="-1">認証管理画面 <a class="header-anchor" href="#認証管理画面" aria-label="Permalink to &quot;認証管理画面&quot;">​</a></h2><p>認証管理画面では、ログイン状態や端末情報を確認できます。</p><p><img src="'+i+'" alt="認証管理" loading="lazy"></p><h2 id="端末管理で見ること" tabindex="-1">端末管理で見ること <a class="header-anchor" href="#端末管理で見ること" aria-label="Permalink to &quot;端末管理で見ること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>ログイン端末</td><td>現在ログインしている端末を確認します</td></tr><tr><td>IP / 位置</td><td>どこからログインしたかの目安になります</td></tr><tr><td>最終アクセス</td><td>端末が最近使われているか確認できます</td></tr><tr><td>解除</td><td>不要または不審な端末のログイン状態を無効化します</td></tr></tbody></table><h2 id="不審なログインを見つけたら" tabindex="-1">不審なログインを見つけたら <a class="header-anchor" href="#不審なログインを見つけたら" aria-label="Permalink to &quot;不審なログインを見つけたら&quot;">​</a></h2><ol><li>該当端末のログインを解除します。</li><li>管理者パスワードや関連トークンを変更します。</li><li>Cloudflare、GitHub、保存先チャンネルなどの認証情報も確認します。</li><li>必要に応じて API Token を再発行します。</li></ol><h2 id="運用のポイント" tabindex="-1">運用のポイント <a class="header-anchor" href="#運用のポイント" aria-label="Permalink to &quot;運用のポイント&quot;">​</a></h2><ul><li>共有 PC ではログインしたままにしないでください。</li><li>管理者権限を持つアカウントは最小限にします。</li><li>定期的にログイン端末を見直します。</li><li>不要な端末や古いセッションは削除します。</li></ul>',19)])])}const P=l(n,[["render",h]]);export{f as __pageData,P as default};
